const input = $('Workflow Input').first().json;

// The Next.js multi-tenant app is already deployed on Vercel.
// New customers are served by passing their slug to the existing deployment
// via Vercel's deployment API — we update the environment variable SITE_PROPS_[SLUG]
// or write the site_props to Supabase and the Next.js app reads it at request time.
//
// ARCHITECTURE NOTE:
// We do NOT create a separate Vercel project per customer.
// The single Next.js app at mysitehq.com.au reads site_props from Supabase
// using the slug from the hostname (slug.mysitehq.com.au → sites WHERE slug=slug).
// A Vercel deployment is only triggered when a new version of the template app is released.
//
// For per-customer previews, we create a Vercel deployment with NEXT_PUBLIC_SITE_SLUG env var.
// The app's middleware routes *.mysitehq.com.au/[slug] to the correct SiteProps.
//
// Per-customer deployment strategy:
// 1. Write site_props to Supabase (done in workflow 03)
// 2. Trigger a Vercel deploy of the main app with updated SITE_DATA env var
//    OR use Vercel's on-demand revalidation to bust the ISR cache for the new slug
// 3. Create a Vercel alias: {slug}.mysitehq.com.au → existing deployment URL
//
// For the spec, we show option B: on-demand ISR revalidation + alias creation.
// This avoids a full Vercel build per customer (which takes 2-3 minutes).
// The app must implement: /api/revalidate?slug=[slug]&secret=[REVALIDATE_SECRET]

const deployStart = Date.now();

return [{
  json: {
    lead_id: input.lead_id,
    site_id: input.site_id,
    slug: input.slug,
    niche: input.niche,
    category: input.category,
    deploy_start: deployStart,
    // The canonical Vercel project URL (set after Vercel project is configured)
    vercel_project_id: process.env.VERCEL_PROJECT_ID || null
  }
}];

const prevInput = $('Build Deployment Payload').first().json;
const raw = $input.first().json;

// Vercel returns { deployments: [{ uid, url, readyState, ... }] }
const deployments = raw.deployments || [];
const latest = deployments[0];

if (!latest) {
  throw new Error('No Vercel deployment found for project ' + $vars.VERCEL_PROJECT_ID);
}

const vercelUrl = 'https://' + latest.url;
const deploymentId = latest.uid;

return [{
  json: {
    lead_id: prevInput.lead_id,
    site_id: prevInput.site_id,
    slug: prevInput.slug,
    deploy_start: prevInput.deploy_start,
    vercel_url: vercelUrl,
    vercel_deployment_id: deploymentId
  }
}];
